import{_ as e,o as s,c as l,a2 as n}from"./chunks/framework.DH0WjybD.js";const h=JSON.parse('{"title":"DOM 操作","description":"","frontmatter":{},"headers":[],"relativePath":"knowledge/dom-manipulation.md","filePath":"knowledge/dom-manipulation.md","lastUpdated":1780755276000}'),o={name:"knowledge/dom-manipulation.md"};function t(r,a,i,p,c,d){return s(),l("div",null,[...a[0]||(a[0]=[n(`<h1 id="dom-操作" tabindex="-1">DOM 操作 <a class="header-anchor" href="#dom-操作" aria-label="Permalink to &quot;DOM 操作&quot;">​</a></h1><h2 id="知识简介" tabindex="-1">知识简介 <a class="header-anchor" href="#知识简介" aria-label="Permalink to &quot;知识简介&quot;">​</a></h2><p>DOM（文档对象模型）操作是通过 JavaScript 读取和修改 HTML 页面结构和内容的基础能力。在 Vue 项目中，一般避免直接操作 DOM，但在某些场景下仍需要。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><ul><li><code>document.getElementById()</code>：通过 ID 获取元素</li><li><code>document.createElement()</code>：创建新元素</li><li><code>$refs</code>：Vue 提供的 DOM 引用方式</li><li><code>setAttribute()</code> / <code>getAttribute()</code>：设置/获取属性</li><li><code>window.location.href</code>：页面跳转</li></ul><h2 id="详细讲解" tabindex="-1">详细讲解 <a class="header-anchor" href="#详细讲解" aria-label="Permalink to &quot;详细讲解&quot;">​</a></h2><p>在项目中，DOM 操作主要用于以下场景：</p><ol><li>通过 <code>$refs</code> 获取 DOM 元素（Vue 推荐方式）：</li></ol><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#79B8FF;">this</span><span style="color:#E1E4E8;">.$refs.file.</span><span style="color:#B392F0;">click</span><span style="color:#E1E4E8;">()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="2"><li>通过 <code>document.getElementById()</code> 获取元素（原生方式）：</li></ol><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#F97583;">var</span><span style="color:#E1E4E8;"> file </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> document.</span><span style="color:#B392F0;">getElementById</span><span style="color:#E1E4E8;">(</span><span style="color:#9ECBFF;">&quot;file&quot;</span><span style="color:#E1E4E8;">)</span></span>
<span class="line"><span style="color:#F97583;">var</span><span style="color:#E1E4E8;"> posterImg </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> document.</span><span style="color:#B392F0;">getElementById</span><span style="color:#E1E4E8;">(</span><span style="color:#9ECBFF;">&#39;poster&#39;</span><span style="color:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ol start="3"><li>通过 <code>setAttribute()</code> 修改元素属性：</li></ol><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#E1E4E8;">img.</span><span style="color:#B392F0;">setAttribute</span><span style="color:#E1E4E8;">(</span><span style="color:#9ECBFF;">&#39;src&#39;</span><span style="color:#E1E4E8;">, base64)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="4"><li>通过 <code>window.location.href</code> 进行页面跳转：</li></ol><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#E1E4E8;">window.location.href </span><span style="color:#F97583;">=</span><span style="color:#9ECBFF;"> &quot;main.html&quot;</span></span>
<span class="line"><span style="color:#E1E4E8;">window.location.href </span><span style="color:#F97583;">=</span><span style="color:#9ECBFF;"> &quot;login.html&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ol start="5"><li>在 supply chain 项目中使用 <code>$router.push()</code> 进行路由跳转（Vue Router 方式）：</li></ol><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#79B8FF;">this</span><span style="color:#E1E4E8;">.$router.</span><span style="color:#B392F0;">push</span><span style="color:#E1E4E8;">(</span><span style="color:#9ECBFF;">&#39;/home&#39;</span><span style="color:#E1E4E8;">)</span></span>
<span class="line"><span style="color:#79B8FF;">this</span><span style="color:#E1E4E8;">.$router.</span><span style="color:#B392F0;">push</span><span style="color:#E1E4E8;">(</span><span style="color:#9ECBFF;">&#39;/login&#39;</span><span style="color:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="重点内容" tabindex="-1">重点内容 <a class="header-anchor" href="#重点内容" aria-label="Permalink to &quot;重点内容&quot;">​</a></h2><ul><li>Vue 中推荐使用 <code>$refs</code> 而非 <code>document.getElementById()</code></li><li><code>window.location.href</code> 会刷新页面，<code>$router.push()</code> 不会</li><li>在 CDN 模式下使用 <code>window.location.href</code>，在 Vue CLI 模式下使用 <code>$router.push()</code></li></ul><h2 id="关键代码示例" tabindex="-1">关键代码示例 <a class="header-anchor" href="#关键代码示例" aria-label="Permalink to &quot;关键代码示例&quot;">​</a></h2><p>来源：<code>frontend/html/signature.html</code> 第 122 行</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#79B8FF;">this</span><span style="color:#E1E4E8;">.$refs.file.</span><span style="color:#B392F0;">click</span><span style="color:#E1E4E8;">()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>来源：<code>frontend/html/signature.html</code> 第 112 行</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#F97583;">var</span><span style="color:#E1E4E8;"> file </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> document.</span><span style="color:#B392F0;">getElementById</span><span style="color:#E1E4E8;">(</span><span style="color:#9ECBFF;">&quot;file&quot;</span><span style="color:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>来源：<code>frontend/html/signature.html</code> 第 158 行</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#E1E4E8;">img.</span><span style="color:#B392F0;">setAttribute</span><span style="color:#E1E4E8;">(</span><span style="color:#9ECBFF;">&#39;src&#39;</span><span style="color:#E1E4E8;">, base64)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>来源：<code>frontend/html/login.html</code> 第 83 行</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#E1E4E8;">window.location.href </span><span style="color:#F97583;">=</span><span style="color:#9ECBFF;"> &quot;main.html&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>来源：<code>供应链—front/src/components/Navigator.vue</code> 第 23 行</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#79B8FF;">this</span><span style="color:#E1E4E8;">.$router.</span><span style="color:#B392F0;">push</span><span style="color:#E1E4E8;">(</span><span style="color:#9ECBFF;">&#39;/home&#39;</span><span style="color:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="实际应用场景" tabindex="-1">实际应用场景 <a class="header-anchor" href="#实际应用场景" aria-label="Permalink to &quot;实际应用场景&quot;">​</a></h2><ul><li>页面跳转</li><li>获取表单元素值</li><li>修改元素样式和属性</li><li>触发文件选择框</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>Vue 中尽量避免直接操作 DOM，优先使用数据驱动</li><li>需要在 <code>mounted</code> 生命周期后才能访问 DOM 元素</li><li><code>window.location.href</code> 会导致页面刷新，丢失当前状态</li></ul><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>误区：在 <code>created</code> 生命周期中访问 DOM 元素</li><li>误区：在 Vue 项目中过度使用 <code>document.getElementById()</code> 而非 <code>$refs</code></li></ul><h2 id="关联知识点" tabindex="-1">关联知识点 <a class="header-anchor" href="#关联知识点" aria-label="Permalink to &quot;关联知识点&quot;">​</a></h2><ul><li><a href="/frontend-knowledge-base/knowledge/vue-router.html">Vue Router</a></li><li><a href="/frontend-knowledge-base/knowledge/filereader.html">FileReader 文件读取</a></li><li><a href="/frontend-knowledge-base/knowledge/canvas-api.html">Canvas API</a></li></ul><h2 id="资料来源" tabindex="-1">资料来源 <a class="header-anchor" href="#资料来源" aria-label="Permalink to &quot;资料来源&quot;">​</a></h2><ul><li>来源文件：<code>frontend/html/signature.html</code> 第 112、122、158 行</li><li>来源文件：<code>frontend/html/login.html</code> 第 83 行</li><li>来源文件：<code>供应链—front/src/components/Navigator.vue</code></li></ul><h2 id="官方资源扩展" tabindex="-1">官方资源扩展 <a class="header-anchor" href="#官方资源扩展" aria-label="Permalink to &quot;官方资源扩展&quot;">​</a></h2><ul><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/API/Document_Object_Model" target="_blank" rel="noreferrer">MDN - DOM 操作</a></li><li>详细介绍 DOM 的 API 和操作方法</li></ul>`,42)])])}const b=e(o,[["render",t]]);export{h as __pageData,b as default};
